class Solution:
    def baseNeg2(self, n: int) -> str:
        if n == 0:
            return "0"
        res = []
        while n:
            n, rem = divmod(n, -2)
            if rem < 0:
                rem += 2
                n += 1
            res.append(str(rem))
        return ''.join(reversed(res))
```
efficiency: HIGH
